989	+use minixrs_kernel_shared::callnr::SYS_GETINFO_NAME_LEN;
990	+use minixrs_kernel_shared::error::{EINVAL, ENOMEM, OK};
991	+
992	+/// Registry key length — a NUL-padded server name. Matches the kernel's
993	+/// `GET_WHOAMI` name field so a server can publish under the name it learns at
994	+/// startup and clients can look it up by the same bytes.
995	+const KEY_LEN: usize = SYS_GETINFO_NAME_LEN;
996	+
997	+/// Registry capacity. Comfortably covers every boot server (≈11) plus slack;
998	+/// no allocator means this is a hard cap, returned as `ENOMEM` when full.
999	+const CAP: usize = 16;
1000	+
1001	+/// One name→endpoint binding. `in_use == false` marks a free slot.
1002	+#[derive(Copy, Clone)]
1003	+struct Entry {
1004	+    key: [u8; KEY_LEN],
1005	+    endpoint: i32,
1006	+    in_use: bool,
1007	+}
1008	+
1009	+impl Entry {
1010	+    const EMPTY: Self = Self {
1011	+        key: [0; KEY_LEN],
1012	+        endpoint: 0,
1013	+        in_use: false,
1014	+    };
1015	+}
1016	+
1017	+/// True if `key` is all-NUL (an unset/empty name). Publishing such a key is
1018	+/// rejected so a zeroed payload can never claim a slot.
1019	+fn key_is_empty(key: &[u8; KEY_LEN]) -> bool {
1020	+    key.iter().all(|&b| b == 0)
1021	+}
1022	+
1023	+/// Publish `ep` under `key`. Re-publishing an existing key updates its endpoint
1024	+/// in place (idempotent, single slot). Returns `OK`, `EINVAL` (empty key), or
1025	+/// `ENOMEM` (table full).
1026	+fn publish_in(t: &mut [Entry; CAP], key: &[u8; KEY_LEN], ep: i32) -> i32 {
1027	+    if key_is_empty(key) {
1028	+        return EINVAL;
1029	+    }
1030	+    // Update an existing binding for this key.
1031	+    for e in t.iter_mut() {
1032	+        if e.in_use && &e.key == key {
1033	+            e.endpoint = ep;
1034	+            return OK;
1035	+        }
1036	+    }
1037	+    // Otherwise claim the first free slot.
1038	+    for e in t.iter_mut() {
1039	+        if !e.in_use {
1040	+            *e = Entry {
1041	+                key: *key,
1042	+                endpoint: ep,
1043	+                in_use: true,
1044	+            };
1045	+            return OK;
1046	+        }
1047	+    }
1048	+    ENOMEM
1049	+}
1050	+
1051	+/// Look up the endpoint registered under `key`, or `None` if unregistered.
1052	+fn retrieve_in(t: &[Entry; CAP], key: &[u8; KEY_LEN]) -> Option<i32> {
1053	+    t.iter()
1054	+        .find(|e| e.in_use && &e.key == key)
1055	+        .map(|e| e.endpoint)
1056	+}
1057	+
1058	+/// True if `key` is registered.
1059	+fn check_in(t: &[Entry; CAP], key: &[u8; KEY_LEN]) -> bool {
1060	+    t.iter().any(|e| e.in_use && &e.key == key)
1061	+}
1062	+
1063	+/// `UnsafeCell`-wrapped static registry. See the module note for the
1064	+/// single-mutator invariant that makes the `Sync` impl sound.
1065	+#[repr(transparent)]
1066	+struct Registry(UnsafeCell<[Entry; CAP]>);
1067	+
1068	+// SAFETY: DS is a single-threaded EL0 process with no interrupt handlers of its
1069	+// own; the table is only ever accessed from DS's straight-line receive loop, so
1070	+// there is never concurrent access.
1071	+unsafe impl Sync for Registry {}
1072	+
1073	+static TABLE: Registry = Registry(UnsafeCell::new([Entry::EMPTY; CAP]));
1074	+
1075	+/// Publish `ep` under `key` in the global registry. Returns `OK` / `EINVAL` /
1076	+/// `ENOMEM` (see [`publish_in`]).
1077	+pub fn publish(key: &[u8; KEY_LEN], ep: i32) -> i32 {
1078	+    // SAFETY: single-mutator invariant (module note); no other reference into
1079	+    // the table is live during DS's straight-line loop.
1080	+    let t = unsafe { &mut *TABLE.0.get() };
1081	+    publish_in(t, key, ep)
1082	+}
1083	+
1084	+/// Look up the endpoint registered under `key` in the global registry.
1085	+pub fn retrieve(key: &[u8; KEY_LEN]) -> Option<i32> {
1086	+    // SAFETY: single-mutator invariant (module note); shared read, no live `&mut`.
1087	+    let t = unsafe { &*TABLE.0.get() };
1088	+    retrieve_in(t, key)
1089	+}
1090	+
1091	+/// True if `key` is registered in the global registry.
1092	+pub fn check(key: &[u8; KEY_LEN]) -> bool {
1093	+    // SAFETY: single-mutator invariant (module note); shared read, no live `&mut`.
1094	+    let t = unsafe { &*TABLE.0.get() };
1095	+    check_in(t, key)
1096	+}
