1134	+        let mut t = [Entry::EMPTY; CAP];
1135	+        assert_eq!(publish_in(&mut t, &key("ds"), 5), OK);
1136	+        assert_eq!(publish_in(&mut t, &key("ds"), 99), OK);
1137	+        assert_eq!(retrieve_in(&t, &key("ds")), Some(99));
1138	+        // Re-publish must not consume a second slot.
1139	+        let used = t.iter().filter(|e| e.in_use).count();
1140	+        assert_eq!(used, 1);
1141	+    }
1142	+
1143	+    #[test]
1144	+    fn distinct_keys_coexist() {
1145	+        let mut t = [Entry::EMPTY; CAP];
1146	+        publish_in(&mut t, &key("vm"), 7);
1147	+        publish_in(&mut t, &key("vfs"), 1);
1148	+        publish_in(&mut t, &key("ds"), 5);
1149	+        assert_eq!(retrieve_in(&t, &key("vm")), Some(7));
1150	+        assert_eq!(retrieve_in(&t, &key("vfs")), Some(1));
1151	+        assert_eq!(retrieve_in(&t, &key("ds")), Some(5));
1152	+    }
1153	+
1154	+    #[test]
1155	+    fn full_table_is_enomem() {
1156	+        let mut t = [Entry::EMPTY; CAP];
1157	+        // Fill every slot with distinct keys.
1158	+        for i in 0..CAP {
1159	+            let mut k = [0u8; KEY_LEN];
1160	+            k[0] = b'a';
1161	+            k[1] = i as u8 + 1; // keep non-empty + distinct
1162	+            assert_eq!(publish_in(&mut t, &k, i as i32), OK);
1163	+        }
1164	+        // A new distinct key has nowhere to go.
1165	+        assert_eq!(publish_in(&mut t, &key("late"), 42), ENOMEM);
1166	+        // But re-publishing an existing key still works (updates in place).
1167	+        let mut existing = [0u8; KEY_LEN];
1168	+        existing[0] = b'a';
1169	+        existing[1] = 1;
1170	+        assert_eq!(publish_in(&mut t, &existing, 1234), OK);
1171	+        assert_eq!(retrieve_in(&t, &existing), Some(1234));
1172	+    }
1173	+
1174	+    #[test]
1175	+    fn prefix_keys_are_distinct() {
1176	+        // "vm" and "vmm" differ only past the second byte; NUL-padding must keep
1177	+        // them distinct (no false prefix match).
1178	+        let mut t = [Entry::EMPTY; CAP];
1179	+        publish_in(&mut t, &key("vm"), 7);
1180	+        publish_in(&mut t, &key("vmm"), 8);
1181	+        assert_eq!(retrieve_in(&t, &key("vm")), Some(7));
1182	+        assert_eq!(retrieve_in(&t, &key("vmm")), Some(8));
1183	+    }
1184	+}
