1191	+/*
1192	+ * minix.rs user-space linker script (aarch64 EL0 servers).
1193	+ *
1194	+ * Produces a static ET_EXEC ELF that the kernel's minimal loader
1195	+ * (`kernel/src/boot_image/elf.rs`) maps segment-by-segment into a fresh
1196	+ * per-process AddrSpace. The loader is deliberately tiny, so this script
1197	+ * keeps every PT_LOAD page-aligned (vaddr *and* file offset) and emits no
1198	+ * dynamic sections / relocations.
1199	+ *
1200	+ * Load base 0x0010_0000 (1 MiB): comfortably below USER_VA_TOP and clear of
1201	+ * the kernel's hand-coded EL0 stub VAs (code 0x40_0000-0x43_0000, stacks
1202	+ * 0x80_0000-0x83_0000, stub-D heap 0x0100_0000). The stack is NOT part of
1203	+ * the ELF — the kernel allocates a stack frame and sets SP_EL0 before eret.
1204	+ * Each server gets its own per-process TTBR0, so this shared load base
1205	+ * never collides across servers.
1206	+ */
1207	+
1208	+OUTPUT_FORMAT(elf64-littleaarch64)
1209	+OUTPUT_ARCH(aarch64)
1210	+ENTRY(_start)
1211	+
1212	+PHDRS {
1213	+    text   PT_LOAD FLAGS(5); /* R+X */
1214	+    rodata PT_LOAD FLAGS(4); /* R   */
1215	+    data   PT_LOAD FLAGS(6); /* RW  */
1216	+}
1217	+
1218	+SECTIONS {
1219	+    . = 0x00100000;
1220	+
1221	+    .text : ALIGN(4K) {
1222	+        KEEP(*(.text._start))
1223	+        *(.text .text.*)
1224	+    } :text
1225	+
1226	+    . = ALIGN(4K);
1227	+    .rodata : ALIGN(4K) {
1228	+        *(.rodata .rodata.*)
1229	+    } :rodata
1230	+
1231	+    . = ALIGN(4K);
1232	+    .data : ALIGN(4K) {
1233	+        *(.data .data.*)
1234	+    } :data
1235	+
1236	+    .bss : ALIGN(4K) {
1237	+        *(.bss .bss.*)
1238	+        *(COMMON)
1239	+    } :data
1240	+
1241	+    /DISCARD/ : {
1242	+        *(.eh_frame)
1243	+        *(.eh_frame_hdr)
1244	+        *(.note .note.*)
1245	+        *(.comment)
1246	+        *(.dynsym .dynstr .hash .gnu.hash .dynamic)
1247	+    }
1248	+}
