    let sef = sef_startup(SefConfig {
        init_fresh: Some(vfs_init),
        signal_handler: None,
    })
    .unwrap_or_else(|_| {
        loop {
            core::hint::spin_loop()
        }
    });

    let mut msg = Message {
        m_source: 0,
        m_type: 0,
        payload: [0u8; 96],
