        let nul = name_field.iter().position(|&b| b == 0).unwrap_or(NAME_LEN);
        let name = core::str::from_utf8(&name_field[..nul]).unwrap_or("");

        let elf = &self.bytes[offset..offset + len];
        (ProcNr::new(proc_nr), name, elf)
    }

